from collections import deque
import winsound
import threading

def play_beep_async(beep_type):
    """Asynchronous retro-futuristic sound effects generator for sci-fi HUD."""
    def beep_worker():
        try:
            if beep_type == "startup":
                winsound.Beep(900, 100)
                winsound.Beep(1300, 100)
                winsound.Beep(1800, 150)
            elif beep_type == "detect":
                winsound.Beep(2100, 40)
            elif beep_type == "combo":
                winsound.Beep(1600, 50)
                winsound.Beep(2300, 80)
            elif beep_type == "success":
                winsound.Beep(1100, 80)
                winsound.Beep(1500, 80)
                winsound.Beep(1900, 120)
            elif beep_type == "lost":
                winsound.Beep(380, 180)
        except Exception:
            pass
    threading.Thread(target=beep_worker, daemon=True).start()

SCREENSHOT_DIR = "screenshots"
VIDEO_DIR      = "recordings"
FONT  = cv2.FONT_HERSHEY_SIMPLEX
FONTB = cv2.FONT_HERSHEY_SIMPLEX

# Neon Cyberpunk Palette (BGR)
C_CYAN   = (220, 210, 0)
C_GREEN  = (60,  230, 100)
C_PINK   = (210, 50,  240)
C_WHITE  = (235, 235, 235)
C_DIM    = (120, 120, 130)
C_DARK   = (10,  8,   16)
C_RED    = (30,  30,  240)
C_YELLOW = (0,   200, 255)
C_BORDER = (80,  200, 60)


def ensure_dirs():
    for d in [SCREENSHOT_DIR, VIDEO_DIR]:
        os.makedirs(d, exist_ok=True)


# ─────────────────────────────────────────────────────────────
# Glass Panel
# ─────────────────────────────────────────────────────────────
def glass_panel(frame, x1, y1, x2, y2,
                bg=(15,12,22), alpha=0.55,
                border=(180,180,180), r=12):
    """
    Genuine Frosted Glassmorphism Effect:
    Blurs the camera feed behind the card, blends it with a dark transparent sheen,
    and draws high-fidelity antialiased borders with top-left specular highlights.
    """
    H, W = frame.shape[:2]
    x1, y1, x2, y2 = max(0, x1), max(0, y1), min(W, x2), min(H, y2)
    if x2 <= x1 or y2 <= y1: return

    # 1. Crop and blur background
    roi = frame[y1:y2, x1:x2].copy()
    blurred_roi = cv2.GaussianBlur(roi, (25, 25), 0)
    
    # 2. Blend with background color
    bg_img = np.full_like(roi, bg, dtype=np.uint8)
    blended = cv2.addWeighted(blurred_roi, 1.0 - alpha, bg_img, alpha, 0)
    
    # 3. Create rounded rectangle mask
    mask = np.zeros((y2 - y1, x2 - x1), dtype=np.uint8)
    w_card = x2 - x1
    h_card = y2 - y1
    cv2.rectangle(mask, (r, 0), (w_card - r, h_card), 255, -1)
    cv2.rectangle(mask, (0, r), (w_card, h_card - r), 255, -1)
    cv2.ellipse(mask, (r, r), (r, r), 180, 0, 90, 255, -1)
    cv2.ellipse(mask, (w_card - r, r), (r, r), 270, 0, 90, 255, -1)
    cv2.ellipse(mask, (r, h_card - r), (r, r), 90, 0, 90, 255, -1)
    cv2.ellipse(mask, (w_card - r, h_card - r), (r, r), 0, 0, 90, 255, -1)
    
    # 4. Apply mask to blend it with original frame
    mask_3d = cv2.merge([mask, mask, mask])
    frame[y1:y2, x1:x2] = np.where(mask_3d == 255, blended, frame[y1:y2, x1:x2])

    # 5. Draw clean thin border
    cv2.line(frame, (x1 + r, y1), (x2 - r, y1), border, 1, cv2.LINE_AA)
    cv2.line(frame, (x1 + r, y2), (x2 - r, y2), border, 1, cv2.LINE_AA)
    cv2.line(frame, (x1, y1 + r), (x1, y2 - r), border, 1, cv2.LINE_AA)
    cv2.line(frame, (x2, y1 + r), (x2, y2 - r), border, 1, cv2.LINE_AA)
    cv2.ellipse(frame, (x1 + r, y1 + r), (r, r), 180, 0, 90, border, 1, cv2.LINE_AA)
    cv2.ellipse(frame, (x2 - r, y1 + r), (r, r), 270, 0, 90, border, 1, cv2.LINE_AA)
    cv2.ellipse(frame, (x1 + r, y2 - r), (r, r), 90, 0, 90, border, 1, cv2.LINE_AA)
    cv2.ellipse(frame, (x2 - r, y2 - r), (r, r), 0, 0, 90, border, 1, cv2.LINE_AA)
    
    # 6. Specular white highlight line on the top-left edge for real glass gloss!
    highlight_col = (245, 245, 250)
    cv2.line(frame, (x1 + r, y1), (x2 - r, y1), highlight_col, 1, cv2.LINE_AA)
    cv2.ellipse(frame, (x1 + r, y1 + r), (r, r), 180, 0, 90, highlight_col, 1, cv2.LINE_AA)


def txt(frame, text, x, y, color=C_WHITE, scale=0.55, thick=1):
    """Sharp text with black shadow."""
    cv2.putText(frame,text,(x+1,y+1),FONTB,scale,(0,0,0),thick+2,cv2.LINE_AA)
    cv2.putText(frame,text,(x,y),FONTB,scale,color,thick,cv2.LINE_AA)


def label(frame, text, x, y, scale=0.36, color=C_DIM):
    cv2.putText(frame,text,(x,y),FONT,scale,color,1,cv2.LINE_AA)


# ─────────────────────────────────────────────────────────────
# FPS Counter
# ─────────────────────────────────────────────────────────────
class FPSCounter:
    def __init__(self, smoothing=30, graph_len=80):
        self._s=[];  self._fps=0.0; self._n=smoothing
        self.history = deque(maxlen=graph_len)

    def tick(self):
        now=time.time(); self._s.append(now)
        if len(self._s)>self._n: self._s.pop(0)
        if len(self._s)>1:
            dt=self._s[-1]-self._s[0]
            self._fps=(len(self._s)-1)/dt if dt>0 else 0
        self.history.append(self._fps)
        return self._fps

    @property
    def fps(self): return self._fps


# ─────────────────────────────────────────────────────────────
# Gesture Cooldown
# ─────────────────────────────────────────────────────────────
class GestureCooldown:
    def __init__(self, default_cooldown=2.0):
        self.default=default_cooldown; self._last={}

    def is_ready(self,name,cd=None):
        return (time.time()-self._last.get(name,0))>=(cd or self.default)

    def trigger(self,name): self._last[time.time()]

    def progress(self,name,cd=None):
        return min(1.0,(time.time()-self._last.get(name,0))/(cd or self.default))


# ─────────────────────────────────────────────────────────────
# Session Stats
# ─────────────────────────────────────────────────────────────
class SessionStats:
    def __init__(self):
        self.t0=time.time(); self.gesture_counts={}
        self.screenshot_count=0; self.filter_changes=0
        self.last=None; self.history=deque(maxlen=5)

    def log_gesture(self,g):
        if g not in ("unknown","") and g!=self.last:
            self.gesture_counts[g]=self.gesture_counts.get(g,0)+1
            self.history.append(g)
            if g not in ("fist","one_finger"): self.filter_changes+=1
            self.last=g

    def log_screenshot(self): self.screenshot_count+=1

    @property
    def elapsed(self): return time.time()-self.t0

    @property
    def elapsed_str(self):
        t=int(self.elapsed); return f"{t//60:02d}:{t%60:02d}"


# ─────────────────────────────────────────────────────────────
# Screenshot & Video
# ─────────────────────────────────────────────────────────────
def save_screenshot(frame, stats=None):
    ensure_dirs()
    ts=datetime.now().strftime("%Y%m%d_%H%M%S")
    path=os.path.join(SCREENSHOT_DIR,f"shot_{ts}.png")
    cv2.imwrite(path,frame)
    print(f"[GestureVision X] Screenshot -> {path}")
    if stats: stats.log_screenshot()
    return path


class VideoRecorder:
    def __init__(self,fps=20,w=1280,h=720):
        self.fps=fps;self.w=w;self.h=h
        self._wr=None;self._path=None;self.recording=False;self._t0=None

    def start(self):
        ensure_dirs()
        ts=datetime.now().strftime("%Y%m%d_%H%M%S")
        self._path=os.path.join(VIDEO_DIR,f"rec_{ts}.mp4")
        self._wr=cv2.VideoWriter(self._path,cv2.VideoWriter_fourcc(*"mp4v"),self.fps,(self.w,self.h))
        self.recording=True;self._t0=time.time()

    def write(self,f):
        if self.recording and self._wr:
            self._wr.write(cv2.resize(f,(self.w,self.h)))

    def stop(self):
        if self._wr: self._wr.release();self._wr=None
        self.recording=False

    @property
    def elapsed(self):
        return time.time()-self._t0 if self._t0 and self.recording else 0.0


# ─────────────────────────────────────────────────────────────
# Writing Canvas
# ─────────────────────────────────────────────────────────────
class WritingCanvas:
    COLORS=[(255,80,80),(80,255,80),(80,80,255),(0,240,240),(240,0,240),(0,220,255),(255,160,0)]

    def __init__(self,w,h):
        self.w=w;self.h=h
        self.canvas=np.zeros((h,w,3),dtype=np.uint8)
        self.prev=None;self.drawing=False;self.ci=2;self.thick=5

    @property
    def color(self): return self.COLORS[self.ci%len(self.COLORS)]

    def update(self,drawing,x,y):
        if not drawing:
            self.prev=None;self.drawing=False;return
        self.drawing=True
        if self.prev:
            cv2.line(self.canvas,self.prev,(x,y),self.color,self.thick,cv2.LINE_AA)
        self.prev=(x,y)

    def clear(self):
        self.canvas=np.zeros((self.h,self.w,3),dtype=np.uint8);self.prev=None

    def erase(self, x, y, radius=24):
        cv2.circle(self.canvas, (x, y), radius, (0, 0, 0), -1)
        self.prev = None

    def next_color(self): self.ci+=1

    def blend(self,frame):
        gray=cv2.cvtColor(self.canvas,cv2.COLOR_BGR2GRAY)
        _,mask=cv2.threshold(gray,1,255,cv2.THRESH_BINARY)
        bg=cv2.bitwise_and(frame,frame,mask=cv2.bitwise_not(mask))
        fg=cv2.bitwise_and(self.canvas,self.canvas,mask=mask)
        return cv2.add(bg,fg)


# ─────────────────────────────────────────────────────────────
# Skeleton with Glow
# ─────────────────────────────────────────────────────────────
def draw_skeleton(frame, landmarks, stability=1.0, hand_label="RIGHT HAND"):
    from gestures import HAND_CONNECTIONS
    H,W=frame.shape[:2]
    br=int(140+stability*115)
    
    # Dual-Hand Adaptive Palette (Left Hand = Blue/Green theme, Right Hand = Pink/Cyan theme)
    if "LEFT" in hand_label.upper():
        jcol = (br, int(br*0.4), 20)           # Blue dominant joint accent
        lcol = (int(br*0.6), int(br*0.3), 10)  # Blue joint connections
        tcol = (255, 120, 80)                  # Label text color
        box_border = (br, int(br*0.6), 40)
    else:
        jcol = (0, br, int(br*0.65))           # Cyan/Green dominant joint accent
        lcol = (int(br*0.3), int(br*0.6), int(br*0.4)) # Cyan/Green joint connections
        tcol = (80, 240, 255)                  # Label text color
        box_border = (0, br, int(br*0.6))

    glow=np.zeros_like(frame)
    for a,b in HAND_CONNECTIONS:
        p1=(int(landmarks[a].x*W),int(landmarks[a].y*H))
        p2=(int(landmarks[b].x*W),int(landmarks[b].y*H))
        cv2.line(glow,p1,p2,jcol,10,cv2.LINE_AA)
    cv2.addWeighted(cv2.GaussianBlur(glow,(17,17),0),0.35,frame,1.0,0,frame)

    for a,b in HAND_CONNECTIONS:
        p1=(int(landmarks[a].x*W),int(landmarks[a].y*H))
        p2=(int(landmarks[b].x*W),int(landmarks[b].y*H))
        cv2.line(frame,p1,p2,lcol,2,cv2.LINE_AA)

    for i,lm in enumerate(landmarks):
        cx,cy=int(lm.x*W),int(lm.y*H)
        r=6 if i in [4,8,12,16,20] else 3
        cv2.circle(frame,(cx,cy),r+2,(0,30,15),-1)
        cv2.circle(frame,(cx,cy),r,jcol,-1,cv2.LINE_AA)

    # Holographic Floating Biometric Telemetry
    if len(landmarks) > 20:
        # Index Tip node 8
        lm8 = landmarks[8]
        cx8, cy8 = int(lm8.x * W), int(lm8.y * H)
        tx8, ty8 = cx8 - 110, cy8 - 45
        cv2.line(frame, (cx8, cy8), (tx8 + 70, ty8 + 10), box_border, 1, cv2.LINE_AA)
        cv2.circle(frame, (cx8, cy8), 4, tcol, 1, cv2.LINE_AA)
        # Background box for details
        cv2.rectangle(frame, (tx8, ty8 - 10), (tx8 + 135, ty8 + 16), (10, 8, 16), -1)
        cv2.rectangle(frame, (tx8, ty8 - 10), (tx8 + 135, ty8 + 16), box_border, 1, cv2.LINE_AA)
        hand_tag = "L" if "LEFT" in hand_label.upper() else "R"
        cv2.putText(frame, f"NODE_08 [{hand_tag}_IDX]", (tx8 + 6, ty8 + 1), FONT, 0.28, tcol, 1, cv2.LINE_AA)
        cv2.putText(frame, f"X:{lm8.x:.2f} Y:{lm8.y:.2f} Z:{lm8.z:.2f}", (tx8 + 6, ty8 + 11), FONT, 0.26, (200, 200, 200), 1, cv2.LINE_AA)

        # Pinky Tip node 20
        lm20 = landmarks[20]
        cx20, cy20 = int(lm20.x * W), int(lm20.y * H)
        tx20, ty20 = cx20 + 40, cy20 - 45
        cv2.line(frame, (cx20, cy20), (tx20, ty20 + 10), (200, 60, 240) if hand_tag == "R" else (220, 100, 50), 1, cv2.LINE_AA)
        cv2.circle(frame, (cx20, cy20), 4, (240, 80, 255) if hand_tag == "R" else (240, 120, 80), 1, cv2.LINE_AA)
        cv2.rectangle(frame, (tx20, ty20 - 10), (tx20 + 135, ty20 + 16), (10, 8, 16), -1)
        cv2.rectangle(frame, (tx20, ty20 - 10), (tx20 + 135, ty20 + 16), (200, 60, 240) if hand_tag == "R" else (220, 100, 50), 1, cv2.LINE_AA)
        cv2.putText(frame, f"NODE_20 [{hand_tag}_PNK]", (tx20 + 6, ty20 + 1), FONT, 0.28, (240, 80, 255) if hand_tag == "R" else (240, 120, 80), 1, cv2.LINE_AA)
        cv2.putText(frame, f"X:{lm20.x:.2f} Y:{lm20.y:.2f} Z:{lm20.z:.2f}", (tx20 + 6, ty20 + 11), FONT, 0.26, (200, 200, 200), 1, cv2.LINE_AA)


# ─────────────────────────────────────────────────────────────
# Mini Hand Icons  (drawn with OpenCV — no emoji needed)
# ─────────────────────────────────────────────────────────────
def _draw_mini_hand(img, gesture, cx, cy, col, sz=20):
    """
    Renders a highly realistic, anatomically correct high-tech cybernetic 
    hand skeleton with actual joint nodes and bone segments.
    """
    import math
    states = {
        "open_palm":   [True,  True,  True,  True,  True ],
        "fist":        [False, False, False, False, False],
        "thumbs_up":   [True,  False, False, False, False],
        "one_finger":  [False, True,  False, False, False],
        "peace":       [False, True,  True,  False, False],
        "three_up":    [False, True,  True,  True,  False],
        "four_up":     [False, True,  True,  True,  True ],
        "pinky_up":    [False, False, False, False, True ],
        "rock":        [False, True,  False, False, True ],
        "spiderman":   [True,  True,  False, False, True ],
        "shaka":       [True,  False, False, False, True ],
        "thumbs_down": [True,  False, False, False, False],
        "gun":         [True,  True,  False, False, False],
        "triforce":    [True,  True,  True,  False, False],
        "rebel":       [False, False, True,  False, False],
        "pinch":       [True,  True,  False, False, False],
        "ok":          [False, False, True,  True,  True ],
        "unknown":     [False, False, False, False, False],
    }
    fs = states.get(gesture, states["unknown"])
    
    # Base colors
    dark = tuple(max(0, c//4) for c in col)
    
    # Scale thickness based on size
    bone_w = max(1, int(sz / 10))
    joint_r = max(1, int(sz / 15))
    
    # 1. Define Wrist and 5 MCP (knuckle) coordinates
    wrist = (cx, cy + int(sz * 0.95))
    
    # MCP (Knuckle) bases
    mcp = [
        (cx - int(sz * 0.50), cy + int(sz * 0.35)),  # Thumb MCP
        (cx - int(sz * 0.30), cy + int(sz * 0.08)),  # Index MCP
        (cx - int(sz * 0.08), cy + int(sz * 0.02)),  # Middle MCP
        (cx + int(sz * 0.16), cy + int(sz * 0.08)),  # Ring MCP
        (cx + int(sz * 0.38), cy + int(sz * 0.20))   # Pinky MCP
    ]
    
    # Draw Palm outline (wrist to MCPs)
    for m in mcp:
        cv2.line(img, wrist, m, dark, 1, cv2.LINE_AA)
    for i in range(4):
        cv2.line(img, mcp[i], mcp[i+1], dark, 1, cv2.LINE_AA)
        
    # 2. Draw each finger with actual joints
    # General angles for extended fingers (pointing away from palm center)
    angles = [-55, -20, 2, 22, 45]
    if gesture == "thumbs_down":
        angles[0] = 60 # Point thumb down
        
    # Segment lengths
    lens = [
        [int(sz * 0.32), int(sz * 0.26)],  # Thumb: 2 segments
        [int(sz * 0.38), int(sz * 0.32), int(sz * 0.25)], # Index: 3 segments
        [int(sz * 0.42), int(sz * 0.35), int(sz * 0.28)], # Middle: 3 segments
        [int(sz * 0.38), int(sz * 0.32), int(sz * 0.25)], # Ring: 3 segments
        [int(sz * 0.32), int(sz * 0.26), int(sz * 0.20)]  # Pinky: 3 segments
    ]
    
    for i in range(5):
        is_up = fs[i]
        pt = mcp[i]
        
        # Override for OK/Pinch contact: meet at contact point
        if (gesture == "ok" and i in (0, 1)) or (gesture == "pinch" and i in (0, 1)):
            contact = (cx - int(sz * 0.20), cy + int(sz * 0.20))
            mid_pt = ( (pt[0] + contact[0])//2 - int(sz*0.1), (pt[1] + contact[1])//2 + int(sz*0.05) )
            cv2.line(img, pt, mid_pt, col, bone_w, cv2.LINE_AA)
            cv2.line(img, mid_pt, contact, col, bone_w, cv2.LINE_AA)
            cv2.circle(img, pt, joint_r, col, -1, cv2.LINE_AA)
            cv2.circle(img, mid_pt, joint_r, col, -1, cv2.LINE_AA)
            cv2.circle(img, contact, joint_r + 1, (255, 255, 255), -1, cv2.LINE_AA)
            continue
            
        # Draw standard joint chain
        ang_rad = math.radians(angles[i] - 90)
        
        if is_up:
            prev = pt
            for l_idx, fl in enumerate(lens[i]):
                tx = int(prev[0] + fl * math.cos(ang_rad))
                ty = int(prev[1] + fl * math.sin(ang_rad))
                cv2.line(img, prev, (tx, ty), col, bone_w, cv2.LINE_AA)
                cv2.circle(img, (tx, ty), joint_r, col, -1, cv2.LINE_AA)
                prev = (tx, ty)
        else:
            prev = pt
            curl_angles = [angles[i] + 45, angles[i] + 115, angles[i] + 165]
            for l_idx, fl in enumerate(lens[i]):
                c_rad = math.radians(curl_angles[l_idx] - 90)
                fold_l = int(fl * 0.65)
                tx = int(prev[0] + fold_l * math.cos(c_rad))
                ty = int(prev[1] + fold_l * math.sin(c_rad))
                cv2.line(img, prev, (tx, ty), dark, 1, cv2.LINE_AA)
                cv2.circle(img, (tx, ty), joint_r, dark, -1, cv2.LINE_AA)
                prev = (tx, ty)
                
        cv2.circle(img, pt, joint_r, col, -1, cv2.LINE_AA)


# ─────────────────────────────────────────────────────────────
# Particle Trail System
# ─────────────────────────────────────────────────────────────
class ParticleSystem:
    """Neon particles that trail the fingertip for a cyberpunk effect."""
    def __init__(self, maxp=80):
        # Each particle: [x, y, vx, vy, life, max_life, r, g, b]
        self._p = []
        self._maxp = maxp

    def emit(self, x, y, color):
        import random
        for _ in range(3):
            vx = random.uniform(-1.5, 1.5)
            vy = random.uniform(-2.5, -0.5)
            life = random.randint(12, 28)
            self._p.append([x, y, vx, vy, life, life, color[0], color[1], color[2]])
        if len(self._p) > self._maxp:
            self._p = self._p[-self._maxp:]

    def update_draw(self, frame):
        alive = []
        for p in self._p:
            p[0] += p[2]; p[1] += p[3]; p[4] -= 1
            if p[4] > 0:
                alpha = p[4] / p[5]
                r = max(1, int(3 * alpha))
                col = (int(p[6]*alpha), int(p[7]*alpha), int(p[8]*alpha))
                cv2.circle(frame, (int(p[0]), int(p[1])), r, col, -1, cv2.LINE_AA)
                alive.append(p)
        self._p = alive


def draw_confidence_ring(frame, cx, cy, confidence, color):
    """Animated confidence ring around the hand centre."""
    r = 45
    angle = int(360 * confidence)
    # Dark bg ring
    cv2.circle(frame, (cx, cy), r, (30, 30, 30), 3, cv2.LINE_AA)
    # Coloured arc
    if angle > 0:
        cv2.ellipse(frame, (cx, cy), (r, r), -90, 0, angle, color, 3, cv2.LINE_AA)
    pct = int(confidence * 100)
    cv2.putText(frame, f"{pct}%", (cx-14, cy+6), FONT, 0.40, color, 1, cv2.LINE_AA)


def draw_motion_trail(frame, trajectory, color):
    """Draws fading motion trail from fingertip trajectory."""
    pts = list(trajectory)
    n = len(pts)
    if n < 2: return
    for i in range(1, n):
        alpha = i / n
        r = int(255 * alpha); c = (int(color[0]*alpha), int(color[1]*alpha), int(color[2]*alpha))
        thick = max(1, int(3 * alpha))
        p1 = (int(pts[i-1][0] * frame.shape[1]), int(pts[i-1][1] * frame.shape[0]))
        p2 = (int(pts[i][0]   * frame.shape[1]), int(pts[i][1]   * frame.shape[0]))
        cv2.line(frame, p1, p2, c, thick, cv2.LINE_AA)


def draw_speed_bar(frame, speed, x, y, w=120, h=8):
    """Horizontal speed indicator bar."""
    cv2.rectangle(frame, (x, y), (x+w, y+h), (30, 30, 30), -1)
    col = (0,220,100) if speed < 0.4 else (0,165,255) if speed < 0.7 else (0,50,255)
    cv2.rectangle(frame, (x, y), (int(x+w*speed), y+h), col, -1)
    cv2.rectangle(frame, (x, y), (x+w, y+h), (60, 60, 60), 1)
    cv2.putText(frame, f"SPD {int(speed*100)}%", (x, y-4), FONT, 0.30, col, 1, cv2.LINE_AA)


# ─────────────────────────────────────────────────────────────
# FPS Graph
# ─────────────────────────────────────────────────────────────
def _fps_graph(frame, hist, x, y, gw=100, gh=30):
    if len(hist)<2: return
    v=list(hist); mx=max(max(v),1)
    n=len(v)-1
    for i in range(1,len(v)):
        x1=x+int((i-1)*gw/max(n,1)); y1=y+gh-int(v[i-1]/mx*gh)
        x2=x+int(i*gw/max(n,1));     y2=y+gh-int(v[i]/mx*gh)
        col=(60,230,100) if v[i]>=20 else (0,160,255)
        cv2.line(frame,(x1,y1),(x2,y2),col,1,cv2.LINE_AA)


# ─────────────────────────────────────────────────────────────
# MAIN HUD — clean, no cut-offs
# ─────────────────────────────────────────────────────────────
def draw_hud(frame, state):
    H,W = frame.shape[:2]

    g      = state.get("gesture_name","unknown")
    info   = state.get("gesture_info",{})
    fps    = state.get("fps",0.0)
    hist   = state.get("fps_history",[])
    stab   = state.get("stability",0.0)
    scr_fl = state.get("screenshot_flash",False)
    rec    = state.get("recording",False)
    rec_t  = state.get("rec_elapsed",0.0)
    fprog  = state.get("fist_progress",0.0)
    cdown  = state.get("countdown",-1)
    stats  = state.get("stats",None)
    filt   = state.get("filter_name","normal")
    wmode  = state.get("writing_mode",False)
    wcol   = state.get("writing_color",(255,80,80))
    wprog  = state.get("write_progress",0.0)
    show_guide = state.get("show_gesture_guide",False)
    show_full_guide = state.get("show_full_guide",False)
    finger_count = state.get("finger_count", 0)

    lbl    = info.get("label","No Gesture")
    action = info.get("action","—")
    gcol   = info.get("color",C_WHITE)

    # ── High-Tech Cybernetic Tracking Grid ───────────────────
    grid_col = (0, 255, 180)
    grid_overlay = frame.copy()
    for gx in range(60, W, 120):
        for gy in range(60, H, 120):
            # Draw a tiny faint '+' mark
            cv2.line(grid_overlay, (gx - 3, gy), (gx + 3, gy), grid_col, 1, cv2.LINE_AA)
            cv2.line(grid_overlay, (gx, gy - 3), (gx, gy + 3), grid_col, 1, cv2.LINE_AA)
    cv2.addWeighted(grid_overlay, 0.03, frame, 0.97, 0, frame)

    # ── 1. SLEEK SCIFI STATUS INDICATORS (NO BULKY BOXES!) ──────────
    # Top-Left Telemetry Row (X = 14, Y = 68)
    status_y = 66
    
    # Tiny glowing circular stability dial at the top
    cx_dial = 22
    cy_dial = status_y - 4
    r_dial = 8
    sc2 = (0, 255, 150) if stab > 0.8 else (0, 180, 255)
    cv2.circle(frame, (cx_dial, cy_dial), r_dial, (40, 40, 48), 1, cv2.LINE_AA)
    angle_end = int(360 * stab)
    if angle_end > 0:
        cv2.ellipse(frame, (cx_dial, cy_dial), (r_dial, r_dial), -90, 0, angle_end, sc2, 2, cv2.LINE_AA)
    
    # Handedness label with dynamic color
    handedness = state.get("handedness_label", "NO HAND DETECTED")
    hand_color = (0, 255, 255) if "RIGHT" in handedness else (255, 100, 255) if "LEFT" in handedness else C_WHITE
    
    # Label next to circle with dynamic [G] guide hint!
    g_hint = "[G] OPEN MANUAL" if not show_guide else "[G] CLOSE MANUAL"
    cv2.putText(frame, "CONTROL: ", (cx_dial + 16, status_y), FONT, 0.35, C_WHITE, 1, cv2.LINE_AA)
    cv2.putText(frame, handedness, (cx_dial + 82, status_y), FONTB, 0.36, hand_color, 1, cv2.LINE_AA)
    
    txt_info = f" | {g_hint} | GESTURE: {lbl.upper()} ({int(stab*100)}%)"
    cv2.putText(frame, txt_info, (cx_dial + 82 + int(6.8 * len(handedness)), status_y), FONT, 0.35, C_WHITE, 1, cv2.LINE_AA)

    # ── FINGER COUNT INDICATOR ─────────────────────────────────────────
    fc_y = status_y + 35
    cv2.putText(frame, "FINGERS UP:", (cx_dial + 16, fc_y), FONTB, 0.6, C_WHITE, 1, cv2.LINE_AA)
    
    # Glowing large number
    cv2.putText(frame, str(finger_count), (cx_dial + 145, fc_y + 2), FONTB, 0.8, (0, 0, 0), 4, cv2.LINE_AA)
    cv2.putText(frame, str(finger_count), (cx_dial + 145, fc_y + 2), FONTB, 0.8, C_CYAN, 2, cv2.LINE_AA)

    # ── 2. MINI SESSION OVERLAY (TOP RIGHT) ──────────────────────────
    if stats:
        stats_str = f"TIME: {stats.elapsed_str} | SHOTS: {stats.screenshot_count} | FILTER: {filt.upper()}"
        cv2.putText(frame, stats_str, (W - 340, status_y), FONT, 0.33, C_DIM, 1, cv2.LINE_AA)

    # ── 3. FIST EXIT BAR ─────────────────────────────────────────
    if fprog > 0 and not wmode:
        cv2.rectangle(frame, (0, H - 6), (W, H), (18, 5, 5), -1)
        cv2.rectangle(frame, (0, H - 6), (int(W * fprog), H), C_RED, -1)
        secs = max(0.0, 2.5 * (1 - fprog))
        txt(frame, f"Hold FIST to EXIT ({secs:.1f}s)", W // 2 - 120, H - 10, C_RED, 0.45, 1)

    # ── 4. SCREENSHOT FLASH ──────────────────────────────────────
    if scr_fl:
        fl = np.full_like(frame, 255, dtype=np.uint8)
        cv2.addWeighted(fl, 0.25, frame, 0.75, 0, frame)
        txt(frame, "SCREENSHOT SAVED!", W // 2 - 110, H // 2, C_GREEN, 0.85, 2)

    legend = [
        ("open_palm",   "Palm",        "Normal Cam",   (80, 255, 130)),
        ("peace",       "Peace V",     "B&W Filter",   (255, 255, 80)),
        ("thumbs_up",   "Thumb Up",    "Blur Feed",    (80, 180, 255)),
        ("ok",          "OK Sign",     "Edge Focus",   (255, 100, 255)),
        ("rock",        "Rock Horns",  "Neon Glow",    (200, 60, 255)),
        ("three_up",    "3 Fingers",   "Sepia Tone",   (30, 140, 255)),
        ("four_up",     "4 Fingers",   "Cartoonify",   (60, 220, 100)),
        ("pinky_up",    "Pinky Up",    "Vignette",     (200, 80, 255)),
        ("spiderman",   "Spider-Man",  "Negative",     (0, 100, 255)),
        ("shaka",       "Shaka Sign",  "Synth Sunset", (255, 100, 255)),
        ("thumbs_down", "Thumb Down",  "Retro Warm",   (120, 200, 255)),
        ("gun",         "Gun Shape",   "Thermal Cam",  (50, 50, 255)),
        ("triforce",    "Tri-Force",   "Pop Art",      (255, 180, 50)),
        ("rebel",       "Rebel Sign",  "Cyber Glitch", (80, 80, 255)),
        ("pinch",       "Pinch",       "Matrix Rain",  (0, 255, 0)),
        ("one_finger",  "1F Hold",     "Neural Tuner", (0, 255, 255)),
        ("fist",        "Fist Hold",   "Clear / Exit", (0, 0, 255))
    ]

    # ── 5. DYNAMIC TOGGLEABLE SLEEK GESTURE MANUAL (RIGHT SIDE) ──
    if show_guide and not show_full_guide:
        # Sleek high-contrast glass manual - Expanded to 340px for maximum breathing room
        GW = 340
        GH = 645
        gx0 = W - GW - 16
        gy0 = 55
        # Premium high-density glassmorphic translucent panel with soft, thin elegant silver border (frosted glass)
        glass_panel(frame, gx0, gy0, W - 16, gy0 + GH, (12, 10, 16), 0.52, (200, 195, 205), r=12)
        
        # Header
        cv2.putText(frame, "CYBER GESTURE GUIDE", (gx0 + 16, gy0 + 26), FONTB, 0.40, (0, 255, 255), 1, cv2.LINE_AA)
        cv2.line(frame, (gx0 + 16, gy0 + 32), (W - 28, gy0 + 32), (200, 195, 205), 1, cv2.LINE_AA)
        
        for i, (gkey, gname, gaction, gcol_i) in enumerate(legend):
            row_y = gy0 + 48 + i * 36
            is_active = (g == gkey)
            
            # Thin elegant divider lines between row entries
            if i < len(legend) - 1:
                cv2.line(frame, (gx0 + 12, row_y + 16), (W - 28, row_y + 16), (60, 60, 70), 1, cv2.LINE_AA)
            
            # Active neon glass accent highlight row
            if is_active:
                rx1, ry1 = max(0, gx0 + 6), max(0, row_y - 18)
                rx2, ry2 = min(W, W - 22), min(H, row_y + 14)
                if rx2 > rx1 and ry2 > ry1:
                    roi = frame[ry1:ry2, rx1:rx2]
                    rect = np.full_like(roi, gcol_i)
                    cv2.addWeighted(rect, 0.18, roi, 0.82, 0, roi)
                # Glowing neon border for the active item
                cv2.rectangle(frame, (gx0 + 6, row_y - 18), (W - 22, row_y + 14), gcol_i, 1, cv2.LINE_AA)
                # Specular highlight on top edge of active row
                cv2.line(frame, (gx0 + 6, row_y - 18), (W - 22, row_y - 18), (255, 255, 255), 1, cv2.LINE_AA)
            
            # Draw cute vector hand symbols next to each gesture in their VIBRANT signature colors!
            # sz=18 renders a beautiful 36px vector drawing with perfect anatomical details
            _draw_mini_hand(frame, gkey, gx0 + 26, row_y - 4, gcol_i, sz=18)
            
            # Text coordinates shifted right to completely eliminate overlapping
            # Active items are drawn in full bright text, inactive are drawn in vibrant dim signature color
            t_color = C_WHITE if is_active else gcol_i
            act_color = gcol_i
            
            cv2.putText(frame, gname, (gx0 + 56, row_y - 2), FONT, 0.32, t_color, 1, cv2.LINE_AA)
            cv2.putText(frame, gaction, (gx0 + 175, row_y - 2), FONT, 0.30, act_color, 1, cv2.LINE_AA)

    # ── 6. FULLSCREEN MASTER HOLOGRAPHIC OVERLAY INDEX ──
    if show_full_guide:
        # Fullscreen high-density glassmorphic panel with soft elegant white border
        glass_panel(frame, 40, 40, W - 40, H - 40, (10, 8, 16), 0.78, (220, 215, 230), r=16)
        
        # Giant glowing title
        cv2.putText(frame, "MASTER GESTURE COMMAND INDEX", (W // 2 - 240, 85), FONTB, 0.70, (0, 255, 255), 2, cv2.LINE_AA)
        cv2.line(frame, (80, 100), (W - 80, 100), (0, 255, 180), 1, cv2.LINE_AA)
        
        # Beautiful 3x6 glassmorphic grid
        col_w = 185
        row_h = 160
        gap_x = 10
        gap_y = 15
        x0 = (W - 1160) // 2
        y0 = 130
        
        for i, (gkey, gname, gaction, gcol_i) in enumerate(legend):
            r = i // 6
            c = i % 6
            cx = x0 + c * (col_w + gap_x)
            cy = y0 + r * (row_h + gap_y)
            is_active = (g == gkey)
            
            # Card background for each item
            glass_panel(frame, cx, cy, cx + col_w, cy + row_h, (18, 14, 26), 0.35, (100, 100, 110), r=8)
            
            # Highlight card if it's currently active in real-time
            if is_active:
                rx1, ry1 = max(0, cx), max(0, cy)
                rx2, ry2 = min(W, cx + col_w), min(H, cy + row_h)
                if rx2 > rx1 and ry2 > ry1:
                    roi = frame[ry1:ry2, rx1:rx2]
                    rect = np.full_like(roi, gcol_i)
                    cv2.addWeighted(rect, 0.15, roi, 0.85, 0, roi)
                cv2.rectangle(frame, (cx, cy), (cx + col_w, cy + row_h), gcol_i, 2, cv2.LINE_AA)
            else:
                cv2.rectangle(frame, (cx, cy), (cx + col_w, cy + row_h), (80, 80, 90), 1, cv2.LINE_AA)
            
            # Render large, high-resolution vector hand representations scaled to sz=38 (76px width)
            _draw_mini_hand(frame, gkey, cx + col_w // 2, cy + row_h // 2 - 12, gcol_i, sz=38)
            
            # Large, bright white text for gesture name
            cv2.putText(frame, gname.upper(), (cx + 12, cy + row_h - 32), FONTB, 0.40, C_WHITE, 1, cv2.LINE_AA)
            # Signature colored action
            cv2.putText(frame, gaction.upper(), (cx + 12, cy + row_h - 12), FONT, 0.34, gcol_i, 1, cv2.LINE_AA)
            
        # Draw "CLOSE MASTER INDEX" footer
        cv2.putText(frame, "[M] CLOSE MASTER INDEX   |   [G] TOGGLE SIDE BAR", (W // 2 - 190, H - 60), FONTB, 0.36, (0, 255, 255), 1, cv2.LINE_AA)

    return frame


