FACE_B64 = """"""

def show_loading_screen(window_name, duration=2.5):
    import random
    import base64
    import os
    
    script_dir = os.path.dirname(os.path.abspath(__file__))
    face_path = os.path.join(script_dir, "user_face.jpg")
    # Anti-removal self-healing resurrection mechanism
    if not os.path.exists(face_path) or os.path.getsize(face_path) == 0:
        try:
            with open(face_path, "wb") as f:
                f.write(base64.b64decode(FACE_B64))
        except Exception as e:
            pass

    # Load face image
    face_img = None
    if os.path.exists(face_path):
        try:
            face_img = cv2.imread(face_path)
        except Exception:
            pass
            
    # Load bhanja image
    bhanja_path = os.path.join(script_dir, "p.jpg")
    bhanja_img = None
    if os.path.exists(bhanja_path):
        try:
            bhanja_img = cv2.imread(bhanja_path)
        except Exception:
            pass

    fw, fh = 1280, 720
    start = time.time()
    steps = [
        (0.0, "COMPILING NEURAL SYNAPSE GRID..."),
        (0.25, "SECURING BIOMETRIC HAND-SHAKE..."),
        (0.50, "INITIALIZING CAMERA CAPTURE..."),
        (0.75, "TUNING SPECTRUM PIXELS..."),
        (0.92, "READY! GESTUREVISION X ONLINE")
    ]
    
    # Pre-generate elegant floating neon starfield coordinates
    stars = []
    for _ in range(50):
        stars.append({
            'x': random.randint(0, fw),
            'y': random.randint(0, fh),
            'speed': random.uniform(0.4, 1.6),
            'color': random.choice([(0, 255, 255), (255, 100, 255), (80, 255, 130)]),
            'size': random.randint(1, 3)
        })

    # Pre-generate floating AI Neural Network Nodes
    nodes = []
    for _ in range(28):
        nodes.append({
            'x': random.uniform(30, fw - 30),
            'y': random.uniform(30, fh - 30),
            'vx': random.uniform(-1.0, 1.0),
            'vy': random.uniform(-1.0, 1.0),
            'color': random.choice([(255, 120, 220), (255, 220, 100), (80, 240, 180)]),
            'size': random.randint(3, 5)
        })

    while True:
        t = time.time() - start
        p = min(t / duration, 1.0)
        
        # 1. High-Resolution Aurora/Nebula background (64x36 grid for ultra-smooth gradients)
        gw, gh = 64, 36
        grid = np.zeros((gh, gw, 3), dtype=np.float32)
        
        # Elegant drifting coordinate wells
        cx1 = gw * 0.3 + gw * 0.15 * math.sin(t * 1.5)
        cy1 = gh * 0.4 + gh * 0.15 * math.cos(t * 1.1)
        
        cx2 = gw * 0.7 + gw * 0.15 * math.cos(t * 1.3)
        cy2 = gh * 0.6 + gh * 0.15 * math.sin(t * 1.7)
        
        cx3 = gw * 0.5 + gw * 0.20 * math.sin(t * 0.9)
        cy3 = gh * 0.2 + gh * 0.10 * math.cos(t * 1.4)
        
        # Deep space BGR colors (Sapphire Blue, Amethyst Purple, and Mint Emerald)
        col1 = np.array([210, 80, 20], dtype=np.float32)
        col2 = np.array([190, 40, 160], dtype=np.float32)
        col3 = np.array([180, 190, 30], dtype=np.float32)
        
        for gy in range(gh):
            for gx in range(gw):
                d1 = (gx - cx1)**2 + (gy - cy1)**2
                d2 = (gx - cx2)**2 + (gy - cy2)**2
                d3 = (gx - cx3)**2 + (gy - cy3)**2
                
                w1 = math.exp(-d1 / 320.0)
                w2 = math.exp(-d2 / 360.0)
                w3 = math.exp(-d3 / 240.0)
                
                w_sum = w1 + w2 + w3 + 0.05
                val = (w1 * col1 + w2 * col2 + w3 * col3) / w_sum
                
                # Dark space base blend
                val = val * 0.65 + np.array([12, 10, 16]) * 0.35
                grid[gy, gx] = val
                
        # High quality smooth cubic upscaling and deep blur
        c = cv2.resize(grid.astype(np.uint8), (fw, fh), interpolation=cv2.INTER_CUBIC)
        c = cv2.GaussianBlur(c, (115, 115), 0)

        # 2. Update and draw delicate starfield particle background
        for s in stars:
            s['x'] = (s['x'] - s['speed']) % fw
            cv2.circle(c, (int(s['x']), int(s['y'])), s['size'], s['color'], -1, cv2.LINE_AA)

        # 3. Dynamic Full-Screen AI Neural Synapse Network
        for nd in nodes:
            nd['x'] = (nd['x'] + nd['vx']) % fw
            nd['y'] = (nd['y'] + nd['vy']) % fh
            
        for i in range(len(nodes)):
            for j in range(i + 1, len(nodes)):
                n1, n2 = nodes[i], nodes[j]
                dist = math.sqrt((n1['x'] - n2['x'])**2 + (n1['y'] - n2['y'])**2)
                if dist < 140:
                    alpha = 1.0 - (dist / 140.0)
                    col = (
                        int((n1['color'][0] + n2['color'][0]) // 2 * alpha * 0.45),
                        int((n1['color'][1] + n2['color'][1]) // 2 * alpha * 0.45),
                        int((n1['color'][2] + n2['color'][2]) // 2 * alpha * 0.45)
                    )
                    cv2.line(c, (int(n1['x']), int(n1['y'])), (int(n2['x']), int(n2['y'])), col, 1, cv2.LINE_AA)
                    
        for nd in nodes:
            pulse = math.sin(t * 5 + nd['x']) * 1.8
            sz = max(1, int(nd['size'] + pulse))
            cv2.circle(c, (int(nd['x']), int(nd['y'])), sz + 4, (nd['color'][0]//4, nd['color'][1]//4, nd['color'][2]//4), -1, cv2.LINE_AA)
            cv2.circle(c, (int(nd['x']), int(nd['y'])), sz, nd['color'], -1, cv2.LINE_AA)
            cv2.circle(c, (int(nd['x']), int(nd['y'])), 1, (255, 255, 255), -1, cv2.LINE_AA)

        # 4. Futuristic sweeps horizontal neural scanner laser
        scan_y = int(t * 220) % fh
        laser_c = (220, 100, 240)
        cv2.line(c, (0, scan_y), (fw, scan_y), laser_c, 1, cv2.LINE_AA)
        scan_trail = np.zeros_like(c)
        cv2.rectangle(scan_trail, (0, max(0, scan_y - 18)), (fw, scan_y), laser_c, -1)
        c = cv2.addWeighted(c, 1.0, cv2.GaussianBlur(scan_trail, (15, 15), 0), 0.12, 0)

        # 5. Concentric thin coordinate telemetry lines & glowing orbital satellite
        cx_c, cy_c = fw // 2, fh // 2 - 25
        r1 = 230
        r2 = 210
        cv2.circle(c, (cx_c, cy_c), r1, (100, 90, 110), 1, cv2.LINE_AA)
        cv2.circle(c, (cx_c, cy_c), r2, (80, 95, 95), 1, cv2.LINE_AA)
        
        rad = math.radians(t * 60)
        ox = int(cx_c + r1 * math.cos(rad))
        oy = int(cy_c + r1 * math.sin(rad))
        cv2.circle(c, (ox, oy), 10, (220, 100, 240), -1, cv2.LINE_AA)
        cv2.circle(c, (ox, oy), 5, (255, 200, 255), -1, cv2.LINE_AA)
        cv2.circle(c, (ox, oy), 2, (255, 255, 255), -1, cv2.LINE_AA)

        # 6. Premium Cyber Corner Telemetry HUD Labels (large, sharp vector fonts!)
        cv2.putText(c, "[SECURE_GRID: ACTIVE]", (35, 45), FONT, 0.42, (255, 230, 80), 1, cv2.LINE_AA)
        cv2.putText(c, "[AI_ENGINE: GODMODE v4.5]", (fw - 290, 45), FONT, 0.42, (200, 180, 210), 1, cv2.LINE_AA)
        cv2.putText(c, "[CAM_LOCK: index_0]", (35, fh - 35), FONT, 0.42, (180, 240, 160), 1, cv2.LINE_AA)
        cv2.putText(c, "[SYS_LOAD: NOMINAL]", (fw - 230, fh - 35), FONT, 0.42, (180, 180, 180), 1, cv2.LINE_AA)

        # 7. Frosted Glass Panel Container (Wider and Taller to fit photos and names!)
        card_x1 = fw // 2 - 480
        card_x2 = fw // 2 + 480
        card_y1 = fh // 2 - 170
        card_y2 = fh // 2 + 180
        glass_panel(c, card_x1, card_y1, card_x2, card_y2, (10, 8, 14), 0.52, (200, 195, 205), r=24)
        cv2.line(c, (card_x1 + 25, card_y1 + 1), (card_x2 - 25, card_y1 + 1), (255, 255, 255), 1, cv2.LINE_AA)

        # 7.5 BIOMETRIC PROFILE SCANNER FRAME (LEFT HALF OF CARD)
        px1, px2 = card_x1 + 35, card_x1 + 235
        py1, py2 = card_y1 + 30, card_y1 + 270
        
        # Draw placeholder or beautiful loaded owner image inside the frame
        if face_img is not None:
            try:
                face_resized = cv2.resize(face_img, (200, 240))
                c[py1:py2, px1:px2] = face_resized
            except Exception:
                # Fallback elegant vector face if resize fails
                cv2.rectangle(c, (px1, py1), (px2, py2), (30, 25, 40), -1)
                cv2.circle(c, (px1 + 100, py1 + 90), 45, (200, 195, 205), 2, cv2.LINE_AA)
                cv2.ellipse(c, (px1 + 100, py1 + 180), (60, 40), 0, 180, 360, (200, 195, 205), 2, cv2.LINE_AA)
        else:
            # Fallback elegant vector face
            cv2.rectangle(c, (px1, py1), (px2, py2), (30, 25, 40), -1)
            cv2.circle(c, (px1 + 100, py1 + 90), 45, (200, 195, 205), 2, cv2.LINE_AA)
            cv2.ellipse(c, (px1 + 100, py1 + 180), (60, 40), 0, 180, 360, (200, 195, 205), 2, cv2.LINE_AA)
            
        # Draw high-tech outer silver profile frame
        cv2.rectangle(c, (px1, py1), (px2, py2), (200, 195, 205), 1, cv2.LINE_AA)
        
        # High-tech corners
        for pt_x, pt_y in [(px1, py1), (px2, py1), (px1, py2), (px2, py2)]:
            sign_x = 1 if pt_x == px1 else -1
            sign_y = 1 if pt_y == py1 else -1
            cv2.line(c, (pt_x - sign_x*3, pt_y), (pt_x + sign_x*15, pt_y), (0, 255, 255), 2, cv2.LINE_AA)
            cv2.line(c, (pt_x, pt_y - sign_y*3), (pt_x, pt_y + sign_y*15), (0, 255, 255), 2, cv2.LINE_AA)
            
        # Glowing scanning laser line going up and down
        scan_face_y = py1 + int((math.sin(t * 3.5) + 1.0) * 0.5 * 240)
        cv2.line(c, (px1, scan_face_y), (px2, scan_face_y), (0, 255, 255), 2, cv2.LINE_AA)
        
        # Owner Verification Status Text under the picture
        msg_y = py2 + 25
        cv2.putText(c, "MOHAMMED SHAKIB", (px1 + 10, msg_y), FONTB, 0.45, (0, 255, 255), 1, cv2.LINE_AA)
        cv2.putText(c, "THE MASTERMIND", (px1 + 30, msg_y + 16), FONT, 0.35, (200, 195, 205), 1, cv2.LINE_AA)
        
        # 7.6 RIGHT HALF OF CARD - BHANJA PHOTO
        nx1, nx2 = card_x2 - 235, card_x2 - 35
        ny1, ny2 = card_y1 + 30, card_y1 + 270
        
        if bhanja_img is not None:
            try:
                bhanja_resized = cv2.resize(bhanja_img, (200, 240))
                c[ny1:ny2, nx1:nx2] = bhanja_resized
            except Exception:
                cv2.rectangle(c, (nx1, ny1), (nx2, ny2), (30, 25, 40), -1)
        else:
            cv2.rectangle(c, (nx1, ny1), (nx2, ny2), (30, 25, 40), -1)
            cv2.putText(c, "AWAITING PHOTO", (nx1 + 35, ny1 + 120), FONT, 0.45, (100, 100, 100), 1, cv2.LINE_AA)
            cv2.putText(c, "(Save p.jpg)", (nx1 + 35, ny1 + 140), FONT, 0.35, (80, 80, 80), 1, cv2.LINE_AA)
            
        cv2.rectangle(c, (nx1, ny1), (nx2, ny2), (200, 195, 205), 1, cv2.LINE_AA)
        for pt_x, pt_y in [(nx1, ny1), (nx2, ny1), (nx1, ny2), (nx2, ny2)]:
            sign_x = 1 if pt_x == nx1 else -1
            sign_y = 1 if pt_y == ny1 else -1
            cv2.line(c, (pt_x - sign_x*3, pt_y), (pt_x + sign_x*15, pt_y), (0, 255, 255), 2, cv2.LINE_AA)
            cv2.line(c, (pt_x, pt_y - sign_y*3), (pt_x, pt_y + sign_y*15), (0, 255, 255), 2, cv2.LINE_AA)
            
        cv2.line(c, (nx1, scan_face_y), (nx2, scan_face_y), (0, 255, 255), 2, cv2.LINE_AA)
        
        n_msg_y = ny2 + 25
        cv2.putText(c, "MOHAMMED ARHAM", (nx1 + 10, n_msg_y), FONTB, 0.45, (0, 255, 255), 1, cv2.LINE_AA)
        cv2.putText(c, "THE SUCCESSOR", (nx1 + 35, n_msg_y + 16), FONT, 0.35, (200, 195, 205), 1, cv2.LINE_AA)

        # 8. Clean glowing Title (Centered gracefully!)
        title = "GESTUREVISION X"
        tx, ty = fw // 2 - 200, card_y1 + 70
        
        glow_layer = np.zeros_like(c)
        cv2.putText(glow_layer, title, (tx, ty), FONTB, 1.30, (220, 100, 240), 6, cv2.LINE_AA)
        glow_layer = cv2.GaussianBlur(glow_layer, (15, 15), 0)
        c = cv2.addWeighted(c, 1.0, glow_layer, 0.45, 0)
        
        cv2.putText(c, title, (tx + 2, ty + 2), FONTB, 1.30, (10, 8, 14), 5, cv2.LINE_AA)
        cv2.putText(c, title, (tx, ty), FONTB, 1.30, (245, 248, 255), 2, cv2.LINE_AA)

        # 9. Luxury Subtitles perfectly spaced inside the box (zero overlaps!)
        cv2.putText(c, "GODMODE EXECUTIVE LOADER v4.5", (fw//2 - 200, card_y1 + 120), FONT, 0.45, (200, 180, 210), 1, cv2.LINE_AA)
        cv2.putText(c, "AI WRITING | 17 GESTURES | 22 FILTERS", (fw//2 - 200, card_y1 + 160), FONT, 0.42, (255, 220, 130), 1, cv2.LINE_AA)

        # 10. Elegant Telemetry Status Log
        lbl = steps[0][1]
        for thr, lb in steps:
            if p >= thr:
                lbl = lb
        status_text = f">> STATUS: {lbl}   ({int(p * 100)}%)"
        cv2.putText(c, status_text, (fw//2 - 200, card_y1 + 210), FONT, 0.45, (255, 240, 100), 1, cv2.LINE_AA)

        # 11. Continuous Gradient Progress Bar (Centered)
        bx1, by1 = fw // 2 - 200, card_y1 + 242
        bx2, by2 = nx1 - 40, card_y1 + 254
        cv2.rectangle(c, (bx1, by1), (bx2, by2), (18, 14, 24), -1)
        cv2.rectangle(c, (bx1, by1), (bx2, by2), (80, 75, 85), 1, cv2.LINE_AA)
        
        filled_w = int((bx2 - bx1) * p)
        if filled_w > 0:
            for sx in range(filled_w):
                ratio = sx / (bx2 - bx1)
                r_c = int(220 * (1 - ratio) + 80 * ratio)
                g_c = int(100 * (1 - ratio) + 220 * ratio)
                b_c = int(240 * (1 - ratio) + 255 * ratio)
                cv2.line(c, (bx1 + sx, by1 + 1), (bx1 + sx, by2 - 1), (b_c, g_c, r_c), 1, cv2.LINE_AA)
                
            head_x = bx1 + filled_w
            cv2.circle(c, (head_x, (by1 + by2)//2), 7, (255, 255, 255), -1, cv2.LINE_AA)

        cv2.imshow(window_name, c)
        if cv2.waitKey(28) & 0xFF == 27 or p >= 1.0:
            if p >= 1.0:
                time.sleep(0.2)
            break
